pub struct SseUsageCollector {
    inner: Arc<SseUsageCollectorInner>,
} and SseUsageCollector: let on_complete: UsageCallbackWithTiming = Arc::new(callback);
        Self {
            inner: Arc::new(SseUsageCollectorInner {
                events: Mutex::new(Vec::new()),
                first_event_time: Mutex::new(None),
                start_time,
                on_complete,
                finished: AtomicBool::new(false), -> the streaming responses arrive incrementally, so the usage info may only become available after multiple events so they need an accumulator containing parsed SSE events, mutex needed because let provider_id = ctx.provider.id.clone(), let mut events = self.inner.events.lock().await;-> different threads can mutate vector at same time, use tokio::sync because it runs in async tasks, async mutex suspends future and allows the runtime to schedule other tasks -> non blocking. Arc<dyn Fn(Vec<Value>, Option<u64>) + Send + Sync> -> execute on different runtime threads, send + sync guarantees thread-safe sharing. let provider_id = ctx.provider.id.clone() -> clone request metadata and move ownership into task              struct SseUsageCollectorInner {
    events: Mutex<Vec<Value>>,
    first_event_time: Mutex<Option<std::time::Instant>>,
    start_time: std::time::Instant,
    on_complete: UsageCallbackWithTiming,
    finished: AtomicBool,
} -> shared because multiple stream chunks can race to request start first, and only one should get it first, finished is atomicbool because it is just a simple flag, it prevents duplicate completion, it is cheaper. In test: fn build_state(db: Arc<Database>) -> ProxyState {
        ProxyState {
            db: db.clone(),
            config: Arc::new(RwLock::new(ProxyConfig::default())),
            status: Arc::new(RwLock::new(ProxyStatus::default())),
            start_time: Arc::new(RwLock::new(None)),
            current_providers: Arc::new(RwLock::new(HashMap::new())),
            provider_router: Arc::new(ProviderRouter::new(db.clone())),
            gemini_shadow: Arc::new(GeminiShadowStore::default()),
            app_handle: None,
            failover_manager: Arc::new(FailoverSwitchManager::new(db)),
        }
    }

run_with_webdav_lock(...).await -> only one operation can run at once, used for concurrent uoloads/downloads, webdav_sync_mutex().lock().await and webdav_sync_service::sync_mutex() in test suggests it uses mutex, it needs to be shared because different async commands may arrive at th same time so it needs to prevent db corruption or inconsistent snapshots etc. let db = state.db.clone(); -> likelly uses arc internally to share db. run_with_webdav_lock(
    webdav_sync_service::download(...)
).await; -> locking for download. let acquired = Arc::new(AtomicBool::new(false)); let acquired_bg = Arc::clone(&acquired); (in test)

WorkerState::scan(paths) -> build walker, install ctrlc handler, bounded channel, receiver threads, worker thread, return exit code. struct WorkerState {
    patterns: Vec<Regex>,
    config: Config,
    quit_flag: Arc<AtomicBool>,
    interrupt_flag: Arc<AtomicBool>,
} -> pattern ans config shared immutably (no lokcing needed), flags shared mutably, use atomicbool instead of mutex, walker.run -> sender threads, ignore::WalkParallel manages threadpool, scope.spawn creates receiver threads, communication between threads uses channels crossbeam_channel::bounded, if receivers are slow, senders  block. struct Batch {
    items: Arc<Mutex<Option<Vec<WorkerResult>>>>,
} -> batching reduces channel traffic, the batch is shared bewteen the sender and receiver thread, the sender keeps appending until flush conditions occur, receiver consumers ownership self.lock().take(), consumes batch Option<Vec<_>> == None, sendser needs to allocate a new batch. flags use atomics instead of mutex because only booleas, with load store fetch, so its cheaper and simpler, Ordering::Relaxed -> flags only signal termination, so no synchronisation of other memory, no ordering guarantees (only eventual visibility). let config = &self.config -> shared read only references across thread -> no synchronisartion needed

